                if *i + n > b.len() {
                    return None;
                }
                let chunk = &b[*i..*i + n];
                if chunk.iter().any(|&c| !(c as char).is_ascii_digit()) {
                    return None;
                }
                let v: i64 = std::str::from_utf8(chunk).ok()?.parse().ok()?;
                *i += n;
                Some(v)
