        // Compute the broken-down UTC fields from an epoch-ms value.
        // Returns (year, month [1-12], day [1-31], hour, minute, second,
        // ms, weekday [0=Sun..6=Sat]).
        fn from_ms(ms_in: f64) -> (i64, i64, i64, i64, i64, i64, i64, i64) {
            if ms_in.is_nan() {
                return (0, 0, 0, 0, 0, 0, 0, 0);
            }
            let ms = ms_in as i64;
            let ms_per_day = 86_400_000i64;
            let mut days = ms.div_euclid(ms_per_day);
            let rem_ms = ms.rem_euclid(ms_per_day);
            let weekday = (((days % 7) + 4) % 7 + 7) % 7; // 1970-01-01 was Thu (4)
            days += 719468;
            let era = if days >= 0 {
                days / 146097
            } else {
                (days - 146096) / 146097
            };
            let doe = days - era * 146097;
            let yoe = (doe - doe / 1460 + doe / 36524 - doe / 146096) / 365;
            let y = yoe + era * 400;
            let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
            let mp = (5 * doy + 2) / 153;
            let day = doy - (153 * mp + 2) / 5 + 1;
            let month = if mp < 10 { mp + 3 } else { mp - 9 };
            let year = if month <= 2 { y + 1 } else { y };
            let hour = rem_ms / 3_600_000;
            let minute = (rem_ms / 60_000) % 60;
            let second = (rem_ms / 1_000) % 60;
            let milli = rem_ms % 1_000;
            (year, month, day, hour, minute, second, milli, weekday)
        }
        // Inverse of from_ms (days_from_civil). Used by the set* mutators.
        // Out-of-range month rolls into year (JS setMonth(13) → next Feb);
        // day/hour/min/sec/ms overflow carries through the linear math.
        fn to_ms(
            year: i64,
            month_1_12: i64,
            day: i64,
            hour: i64,
            minute: i64,
            second: i64,
            milli: i64,
        ) -> f64 {
            let m0 = month_1_12 - 1;
            let year = year + m0.div_euclid(12);
            let month = m0.rem_euclid(12) + 1;
            let y = if month <= 2 { year - 1 } else { year };
            let era = (if y >= 0 { y } else { y - 399 }) / 400;
            let yoe = y - era * 400;
            let mp = if month > 2 { month - 3 } else { month + 9 };
            let doy = (153 * mp + 2) / 5 + day - 1;
            let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy;
            let days = era * 146097 + doe - 719468;
            (days as f64) * 86_400_000.0
                + (hour as f64) * 3_600_000.0
                + (minute as f64) * 60_000.0
                + (second as f64) * 1_000.0
                + (milli as f64)
        }
