    #[test]
    fn class_with_getter_setter_and_async() {
        // Real accessor semantics: `get value`/`set value` install a live
        // accessor on the instance, invoked transparently by `b.value` /
        // `b.value = x`. An `async` method returns a promise (ECMA-262 §27.7),
        // so its result is consumed via `.then` (settled-promise reaction runs
        // when microtasks drain at the end of `run`).
        let (_, out) = run("class Box {\
               constructor() { this._v = 10; }\
               get value() { return this._v + 5; }\
               set value(x) { this._v = x; }\
               async fetch() { return 99; }\
             }\
             const b = new Box();\
             console.log(b.value);\
             b.value = 42;\
             console.log(b._v);\
             b.fetch().then(v => console.log(v));");
        assert_eq!(out, vec!["15", "42", "99"]);
    }

