    #[test]
    fn bigint_tostring_honors_radix() {
        // BigInt.prototype.toString(radix) must convert to the given base,
        // not silently return base-10. Crypto libs (noble-curves) derive a
        // field's bit length via `n.toString(2).length`; a base-10-only
        // toString corrupts every curve's modulus (e.g. an Ed25519
        // coordinate bound collapsing from 2^255 to 2^80). Regression for
        // the explorer.hyvechain.com "valid coordinate" crypto failure.
        let (_, out) = run("console.log((255n).toString(2)); \
             console.log((256n).toString(16)); \
             let p = 2n ** 255n - 19n; \
             console.log(p.toString(2).length); \
             console.log(p.toString(16).length); \
             console.log((0n).toString(2)); \
             console.log((-255n).toString(16));");
        assert_eq!(out, vec!["11111111", "100", "255", "64", "0", "-ff"]);
    }

