    #[test]
    fn hot_numeric_per_function_loop_is_correct() {
        // A JIT-eligible pure-numeric function called many times through the
        // per-function path must stay correct (with CV_JIT set it switches to
        // native code mid-loop; without, it stays on the VM — both must match).
        // instanceof forces whole-script fallback so `sq` goes through the
        // per-function path. sum of k*k, k=0..39 = 20540.
        let mut i = Interp::new();
        i.install_basic_globals();
        i.run(
            "var fb = (function(){}) instanceof Object;\
             function sq(n){ return n * n; }\
             var t = 0;\
             for (var k = 0; k < 40; k++) { t = t + sq(k); }\
             console.log(t);",
        )
        .unwrap();
        assert_eq!(i.output, vec!["20540"]);
    }

