    #[test]
    fn object_literal_proto_sets_prototype_not_own_key() {
        // `{__proto__: null, …}` (rollup/webpack namespace idiom) must set
        // the prototype, NOT create an own "__proto__" key — otherwise it
        // leaks into Object.keys/for-in and value-iteration yields the
        // prototype (chart.js registered the null prototype as a component).
        let (_, out) = run("var ns = {__proto__: null, a: 1, b: 2}; \
             console.log(Object.keys(ns).join(',')); \
             console.log(ns.a + ',' + ns.b); \
             var p = {tag: 'proto'}; var o = {__proto__: p, x: 9}; \
             console.log(Object.keys(o).join(',')); \
             console.log(o.tag);");
        // keys exclude __proto__; data props still read; prototype inherited.
        assert_eq!(out, vec!["a,b", "1,2", "x", "proto"]);
    }

    #[test]
    fn subclass_inherits_static_members() {
        // `class B extends A` sets B.[[Prototype]] = A, so B inherits A's
        // static field + static method; a third level inherits transitively.
        // (chart.js registers components by reading a static `id` declared
        // on a base class through the subclass.)
        let (_, out) = run(
            "class A { static id = 'line'; static make() { return 'm'; } } \
             class B extends A {} \
             class C extends B {} \
             console.log(B.id); console.log(B.make()); console.log(C.id); \
             console.log(typeof C.make);",
        );
        assert_eq!(out, vec!["line", "m", "line", "function"]);
    }

