    #[test]
    fn walletconnect_module_39265_exports_provider_from_real_chunk() {
        let chunk = std::fs::read_to_string(format!(
            "{}/../../tools/explorer_9265.js",
            env!("CARGO_MANIFEST_DIR")
        ))
        .expect("read explorer_9265.js");
        let marker = "39265:function(e,t,r){";
        let start = chunk.find(marker).expect("39265 marker") + marker.len();
        let mut depth = 1i32;
        let mut end = start;
        for (off, ch) in chunk[start..].char_indices() {
            match ch {
                '{' => depth += 1,
                '}' => {
                    depth -= 1;
                    if depth == 0 {
                        end = start + off;
                        break;
                    }
                }
                _ => {}
            }
        }
        assert!(end > start, "module body end");
        let body = &chunk[start..end];
        let mut interp = Interp::new();
        interp.install_basic_globals();
        interp.install_math();
        interp
            .run(
                "var e = { exports: {} };\n\
                 var t = e.exports;\n\
                 var r = function(id) {\n\
                   if (id === 49010) {\n\
                     return { hE: function(fn) { return fn; } };\n\
                   }\n\
                   return {};\n\
                 };\n\
                 r.d = function(target, defs) {\n\
                   for (var k in defs) Object.defineProperty(target, k, { enumerable: true, get: defs[k] });\n\
                 };\n\
                 r.n = function(mod) { return function() { return mod; }; };\n\
                 r.e = function() { return Promise.resolve(); };\n\
                 function TextEncoder() { this.encode = function(s) { return s; }; }\n\
                 function TextDecoder() { this.decode = function(s) { return s; }; }\n\
                 var window = globalThis;\n\
                 var navigator = {};\n\
                 var document = {};",
            )
            .expect("install module stubs");
        let stmts = crate::parser::parse_program(body).expect("parse 39265 body");
        let g = interp.global.clone();
        interp.hoist_vars_into(&stmts, &g);
        // Mirror exec_block's function hoisting while letting the test
        // surface the exact statement index that diverges.
        for stmt in &stmts {
            if let crate::ast::Stmt::FunctionDecl { name, params, body } = stmt {
                let f = Value::Function(Rc::new(FunctionValue {
                    name: Some(name.clone()),
                    params: params.clone(),
                    body: FunctionBody::Block(body.clone()),
                    closure: g.clone(),
                    props: RefCell::new(HashMap::new()),
                    is_arrow: false,
                }));
                scope_define(&g, name, f, false);
            }
        }
        for (idx, stmt) in stmts.iter().enumerate() {
            if let Err(err) = interp.exec_stmt(stmt, &g) {
                panic!("stmt #{idx} failed: {err:?}\nstmt={stmt:?}");
            }
        }
        interp.drain_microtasks();
        interp
            .run(
                "console.log(typeof e.exports.EthereumProvider);\n\
             console.log(typeof e.exports.EthereumProvider?.init);",
            )
            .expect("inspect exports");
        assert_eq!(interp.output, vec!["function", "function"]);
    }

    #[test]
    fn walletconnect_module_39265_ast_keeps_provider_alias_decl() {
        let chunk = std::fs::read_to_string(format!(
            "{}/../../tools/explorer_9265.js",
            env!("CARGO_MANIFEST_DIR")
        ))
        .expect("read explorer_9265.js");
        let marker = "39265:function(e,t,r){";
        let start = chunk.find(marker).expect("39265 marker") + marker.len();
        let mut depth = 1i32;
        let mut end = start;
        for (off, ch) in chunk[start..].char_indices() {
            match ch {
                '{' => depth += 1,
                '}' => {
                    depth -= 1;
                    if depth == 0 {
                        end = start + off;
                        break;
                    }
                }
                _ => {}
            }
        }
        assert!(end > start, "module body end");
        let body = &chunk[start..end];
        let ast = crate::parser::parse_program(body).expect("parse 39265 body");
        let has_hg_decl = ast.iter().any(|stmt| match stmt {
            crate::ast::Stmt::VarDecl { decls, .. } => decls.iter().any(|d| d.name == "hg"),
            _ => false,
        });
        assert!(has_hg_decl, "expected `let hg = hf` decl in parsed module");
    }

    #[test]
    fn import_export_skipped_not_fatal() {
        let (_, out) = run("import { x } from 'whatever'; export const y = 5; console.log('ok');");
        assert_eq!(out, vec!["ok"]);
    }

    // ===================== ES MODULE GRAPH TESTS (§16.2) =====================

    /// Run an ES module graph from an in-memory file set. `files` maps a URL to
    /// its source; `entry` names the entry module. The loader resolves relative
    /// specifiers against the referrer with a tiny URL-join so `./b.js` works.
    fn run_module_files(files: &[(&str, &str)], entry: &str) -> Vec<String> {
        let map: std::collections::HashMap<String, String> = files
            .iter()
            .map(|(k, v)| (k.to_string(), v.to_string()))
            .collect();
        let map_rc = std::rc::Rc::new(map);
        let loader_map = map_rc.clone();
        let mut i = Interp::new();
        i.install_basic_globals();
        i.set_module_loader(std::rc::Rc::new(move |spec: &str, referrer: &str| {
            let resolved = test_resolve_specifier(spec, referrer);
            loader_map
                .get(&resolved)
                .map(|src| (resolved.clone(), src.clone()))
        }));
        let entry_src = map_rc.get(entry).expect("entry source").clone();
        match i.run_module_graph(entry, &entry_src) {
            Ok(_) => {}
            Err(JsError::Throw(v)) => {
                let msg = if let Value::Object(o) = &v {
                    let b = o.borrow();
                    let name = b.get("name").map(|x| x.to_display_string()).unwrap_or_default();
                    let m = b.get("message").map(|x| x.to_display_string()).unwrap_or_default();
                    format!("{name}: {m}")
                } else {
                    v.to_display_string()
                };
                panic!("module graph threw: {msg}");
            }
            Err(e) => panic!("module graph error: {e:?}"),
        }
        i.output
    }

    /// Minimal module-specifier resolver for tests: joins `./x`, `../x`, and
    /// bare `x` against the referrer's directory; absolute `/x` and `proto:` are
    /// returned as-is. (The real browser uses cv_url; this keeps tests
    /// dependency-free while exercising relative resolution.)
    fn test_resolve_specifier(spec: &str, referrer: &str) -> String {
        if spec.contains("://") || spec.starts_with('/') {
            return spec.to_string();
        }
        // Directory of the referrer.
        let dir = match referrer.rfind('/') {
            Some(i) => &referrer[..i],
            None => "",
        };
        let mut parts: Vec<&str> = if dir.is_empty() {
            Vec::new()
        } else {
            dir.split('/').collect()
        };
        for seg in spec.split('/') {
            match seg {
                "." | "" => {}
                ".." => {
                    parts.pop();
                }
                other => parts.push(other),
            }
        }
        parts.join("/")
    }

    #[test]
    fn module_import_sees_dependency_export() {
        // A imports v from B; the value B exported must be visible in A.
        let out = run_module_files(
            &[
                ("app/a.js", "import { v } from './b.js'; console.log(v);"),
                ("app/b.js", "export const v = 42;"),
            ],
            "app/a.js",
        );
        assert_eq!(out, vec!["42"]);
    }

    #[test]
    fn module_dependency_evaluates_before_importer() {
        // B's side-effect log must come BEFORE A's (post-order: deps first).
        let out = run_module_files(
            &[
                (
                    "a.js",
                    "import './b.js'; console.log('A');",
                ),
                ("b.js", "console.log('B');"),
            ],
            "a.js",
        );
        assert_eq!(out, vec!["B", "A"]);
    }

    #[test]
    fn module_diamond_evaluates_shared_dep_once() {
        // A -> B, C ; B -> D ; C -> D. D must evaluate exactly ONCE.
        let out = run_module_files(
            &[
                (
                    "a.js",
                    "import './b.js'; import './c.js'; console.log('A');",
                ),
                ("b.js", "import './d.js'; console.log('B');"),
                ("c.js", "import './d.js'; console.log('C');"),
                ("d.js", "console.log('D');"),
            ],
            "a.js",
        );
        // D once, before both B and C; A last.
        assert_eq!(out, vec!["D", "B", "C", "A"]);
        assert_eq!(out.iter().filter(|l| *l == "D").count(), 1);
    }

    #[test]
    fn module_live_binding_reflects_later_mutation() {
        // B exports a `let` and a mutator; A reads it before and after the
        // mutation. The imported binding must be LIVE (§16.2.1.4.2).
        let out = run_module_files(
            &[
                (
                    "a.js",
                    "import { count, inc } from './b.js'; \
                     console.log(count); inc(); inc(); console.log(count);",
                ),
                (
                    "b.js",
                    "export let count = 0; export function inc(){ count++; }",
                ),
            ],
            "a.js",
        );
        assert_eq!(out, vec!["0", "2"]);
    }

    #[test]
    fn module_default_export_and_import() {
        let out = run_module_files(
            &[
                ("a.js", "import greet from './b.js'; console.log(greet('x'));"),
                ("b.js", "export default function(n){ return 'hi ' + n; }"),
            ],
            "a.js",
        );
        assert_eq!(out, vec!["hi x"]);
    }

    #[test]
    fn module_named_default_function_export_and_mixed_import() {
        // `export default function Name(){}` (a NAMED default HoistableDeclaration)
        // plus a named export, consumed in ONE `import Def, { Named } from`
        // statement — the exact shape webpack/Vite emit. The parser wraps the
        // declaration + its synthetic `*default*` binding in a Block;
        // `evaluate_module_body` must splice that block into the MODULE scope so
        // both `*default*` and the named export resolve for importers (§16.2.1.6.4
        // InitializeEnvironment; matches V8 default HoistableDeclaration binding).
        let out = run_module_files(
            &[
                (
                    "index.js",
                    "import makeLogger, { LEVEL } from './logger.js'; \
                     const log = makeLogger('app'); \
                     console.log(log('hi') + ' lvl=' + LEVEL);",
                ),
                (
                    "logger.js",
                    "export const LEVEL = 'info'; \
                     export default function makeLogger(tag){ \
                       return function(msg){ return '[' + tag + '] ' + msg; }; \
                     }",
                ),
            ],
            "index.js",
        );
        assert_eq!(out, vec!["[app] hi lvl=info"]);
    }

    #[test]
    fn module_named_default_function_is_callable_within_own_module() {
        // The named default function must ALSO be callable by its own name
        // inside the defining module (it binds both `*default*` AND `Name`).
        let out = run_module_files(
            &[(
                "m.js",
                "export default function square(n){ return n * n; } \
                 console.log('sq=' + square(5));",
            )],
            "m.js",
        );
        assert_eq!(out, vec!["sq=25"]);
    }

    #[test]
    fn module_cyclic_function_exports_resolve() {
        // Mutually-recursive function exports across a cycle (even <-> odd).
        // Both modules' function decls must be hoisted into their module envs
        // before either body runs the recursion, so the cross-module imported
        // function names resolve. (Distinct from `module_cycle_terminates`,
        // which only checks the cycle does not infinite-loop with const exports.)
        let out = run_module_files(
            &[
                (
                    "even.js",
                    "import { isOdd } from './odd.js'; \
                     export function isEven(n){ return n === 0 ? true : isOdd(n - 1); } \
                     console.log('isEven(4)=' + isEven(4));",
                ),
                (
                    "odd.js",
                    "import { isEven } from './even.js'; \
                     export function isOdd(n){ return n === 0 ? false : isEven(n - 1); }",
                ),
            ],
            "even.js",
        );
        assert_eq!(out, vec!["isEven(4)=true"]);
    }

    #[test]
    fn module_named_default_class_export_and_import() {
        // The class analogue of the above: `export default class C {}` consumed
        // by a default import in another module.
        let out = run_module_files(
            &[
                (
                    "app.js",
                    "import Widget from './widget.js'; \
                     const w = new Widget(3); console.log('area=' + w.area());",
                ),
                (
                    "widget.js",
                    "export default class Widget { \
                       constructor(s){ this.s = s; } \
                       area(){ return this.s * this.s; } \
                     }",
                ),
            ],
            "app.js",
        );
        assert_eq!(out, vec!["area=9"]);
    }

    #[test]
    fn module_namespace_import_is_live() {
        let out = run_module_files(
            &[
                (
                    "a.js",
                    "import * as m from './b.js'; \
                     console.log(m.count); m.bump(); console.log(m.count);",
                ),
                (
                    "b.js",
                    "export let count = 1; export function bump(){ count += 10; }",
                ),
            ],
            "a.js",
        );
        // Namespace property reads are live getters → reflect the mutation.
        assert_eq!(out, vec!["1", "11"]);
    }

