    #[test]
    fn plain_for_of_does_not_await_iterated_values() {
        let mut i = Interp::new();
        i.install_basic_globals();
        i.install_promise();
        i.run(
            "const iterable = { \
                [Symbol.iterator]: function() { \
                    let done = false; \
                    return { next: function() { \
                        if (done) return { done: true }; \
                        done = true; \
                        return { done: false, value: Promise.resolve(7) }; \
                    } }; \
                } \
            }; \
            for (const v of iterable) { \
                console.log(typeof v); \
                console.log(typeof v.then); \
            }",
        )
        .unwrap();
        assert_eq!(i.output, vec!["object", "function"]);
    }

    #[test]
    fn for_await_unwraps_iterated_promise_values() {
        let mut i = Interp::new();
        i.install_basic_globals();
        i.install_promise();
        i.run(
            "const iterable = { \
                [Symbol.iterator]: function() { \
                    let done = false; \
                    return { next: function() { \
                        if (done) return { done: true }; \
                        done = true; \
                        return { done: false, value: Promise.resolve(7) }; \
                    } }; \
                } \
            }; \
            for await (const v of iterable) { console.log(v); }",
        )
        .unwrap();
        assert_eq!(i.output, vec!["7"]);
    }

    #[test]
    fn for_loop_sum() {
        let (_, out) =
            run("let s = 0; for (let i = 1; i <= 10; i = i + 1) { s = s + i; } console.log(s);");
        assert_eq!(out, vec!["55"]);
    }

    // --- async/await true suspension (state-machine lowering) ---

    #[test]
    fn async_await_chrome_ordering() {
        // An async body runs SYNCHRONOUSLY up to the first `await`, returns a
        // pending promise, lets the caller continue, then resumes on a
        // microtask — exactly V8/Chrome ordering.
        let out = run_async(
            "async function f(){ console.log('start'); var a = await Promise.resolve(10); \
             console.log('a' + a); return a; } \
             console.log('before'); \
             f().then(function(v){ console.log('done' + v); }); \
             console.log('after');",
        );
        assert_eq!(out, vec!["before", "start", "after", "a10", "done10"]);
    }

    #[test]
    fn async_sequential_awaits_thread_values() {
        let out = run_async(
            "async function f(){ var a = await Promise.resolve(2); \
             var b = await Promise.resolve(a * 3); return a + b; } \
             f().then(function(v){ console.log(v); });",
        );
        assert_eq!(out, vec!["8"]);
    }

    #[test]
    fn async_try_catch_catches_awaited_rejection() {
        let out = run_async(
            "async function f(){ try { await Promise.reject(new Error('boom')); \
             console.log('unreached'); } catch (e) { console.log('caught:' + e.message); } \
             return 'ok'; } \
             f().then(function(v){ console.log('res:' + v); });",
        );
        assert_eq!(out, vec!["caught:boom", "res:ok"]);
    }

    #[test]
    fn async_awaits_foreign_thenable() {
        // A non-native thenable (core-js-style polyfilled Promise) is adopted.
        let out = run_async(
            "var thenable = { then: function(res){ res(42); } }; \
             async function f(){ var x = await thenable; console.log('x' + x); return x; } \
             f().then(function(v){ console.log('r' + v); });",
        );
        assert_eq!(out, vec!["x42", "r42"]);
    }

    #[test]
    fn async_machine_throw_after_await_rejects_result() {
        let out = run_async(
            "async function f(){ await Promise.resolve(0); throw new Error('x'); } \
             f().then(function(){ console.log('bad'); }, \
                      function(e){ console.log('rej:' + e.message); });",
        );
        assert_eq!(out, vec!["rej:x"]);
    }

    #[test]
    fn async_if_branch_with_await() {
        let out = run_async(
            "async function f(n){ if (n > 0) { var r = await Promise.resolve('pos'); \
             return r; } return 'neg'; } \
             f(1).then(function(v){ console.log('hi:' + v); });",
        );
        assert_eq!(out, vec!["hi:pos"]);
    }

    #[test]
    fn async_if_else_no_await_in_taken_branch() {
        let out = run_async(
            "async function f(n){ if (n > 0) { return await Promise.resolve('pos'); } \
             return 'neg'; } \
             f(-1).then(function(v){ console.log('lo:' + v); });",
        );
        assert_eq!(out, vec!["lo:neg"]);
    }

    #[test]
    fn async_for_of_await() {
        let out = run_async(
            "async function f(){ var s = 0; for (var x of [1, 2, 3]) { s += await Promise.resolve(x); } \
             return s; } f().then(function(v){ console.log(v); });",
        );
        assert_eq!(out, vec!["6"]);
    }

    #[test]
    fn async_while_await() {
        let out = run_async(
            "async function f(){ var i = 0, s = 0; while (i < 3) { s += await Promise.resolve(i); i = i + 1; } \
             return s; } f().then(function(v){ console.log(v); });",
        );
        assert_eq!(out, vec!["3"]);
    }

    #[test]
    fn async_for_await_break_continue() {
        // i=0 → +0, i=1 → continue, i=2 → +2, i=3 → +3, i=4 → break ⇒ 5.
        let out = run_async(
            "async function f(){ var s = 0; for (var i = 0; i < 9; i = i + 1) { \
             if (i === 1) continue; if (i === 4) break; s += await Promise.resolve(i); } return s; } \
             f().then(function(v){ console.log(v); });",
        );
        assert_eq!(out, vec!["5"]);
    }

    #[test]
    fn async_loop_var_does_not_shadow_outer() {
        // A `let` loop variable must be block-scoped and not leak past the loop
        // to shadow an enclosing binding of the same name — the bug that left
        // tsparticles' `new Promise(t => { for (let t of …) …; t() })` calling
        // the last loop value instead of the promise's `resolve`.
        let out = run_async(
            "async function f(){ var t = function(){ return 'resolved'; }; var sum = 0; \
             for (let t of [1, 2, 3]) { sum += await Promise.resolve(t); } \
             return t() + ':' + sum; } \
             f().then(function(v){ console.log(v); }, function(){ console.log('ERR'); });",
        );
        assert_eq!(out, vec!["resolved:6"]);
    }

    #[test]
    fn optional_call_binds_this_and_short_circuits() {
        // `o?.m()` binds `this = o`; `null?.m()` short-circuits to undefined
        // (no throw); `arr?.forEach(cb)` calls with the array receiver.
        let (_, out) = run("var o = { x: 7, getX: function(){ return this.x; } }; \
             console.log(o?.getX()); \
             var n = null; \
             console.log(n?.getX()); \
             var arr = [1, 2, 3]; var s = 0; arr?.forEach(function(v){ s += v; }); \
             console.log(s);");
        assert_eq!(out, vec!["7", "undefined", "6"]);
    }

    #[test]
    fn array_and_object_access() {
        let (_, out) = run(
            "const xs = [10, 20, 30]; console.log(xs.length); console.log(xs[1]); const o = { name: 'Toasty' }; console.log(o.name);",
        );
        assert_eq!(out, vec!["3", "20", "Toasty"]);
    }

    #[test]
    fn arrow_fn_and_higher_order() {
        let (_, out) = run(
            "const inc = x => x + 1; const apply = (f, v) => f(v); console.log(apply(inc, 41));",
        );
        assert_eq!(out, vec!["42"]);
    }

    #[test]
    fn string_concat_and_typeof() {
        let (_, out) = run(
            "console.log('answer = ' + (40 + 2)); console.log(typeof 1); console.log(typeof 'x');",
        );
        assert_eq!(out, vec!["answer = 42", "number", "string"]);
    }

