    #[test]
    fn math_builtins() {
        let i = Interp::new();
        i.install_math();
        let mut i = i;
        i.run(
            "console.log(Math.sqrt(16));\
             console.log(Math.floor(3.7));\
             console.log(Math.ceil(3.2));\
             console.log(Math.round(2.5));\
             console.log(Math.max(1, 5, 3));\
             console.log(Math.min(1, 5, 3));\
             console.log(Math.abs(-7));\
             console.log(Math.pow(2, 10));",
        )
        .unwrap();
        assert_eq!(i.output, vec!["4", "3", "4", "3", "5", "1", "7", "1024"]);
    }

    /// ECMA-262 §21.3.2.28: Math.round uses half-toward-+Infinity.
    /// Critically, Math.round(-0.5) = -0 (not -1 and not +0).
    #[test]
    fn math_round_half_toward_plus_infinity() {
        let i = Interp::new();
        i.install_math();
        let mut i = i;
        // Infinity and -Infinity expressed as 1/0 and -1/0 to avoid
        // requiring install_globals() for the Infinity binding.
        i.run(
            "console.log(Math.round(0.5));\n\
             console.log(Math.round(-0.5));\n\
             console.log(Math.round(-1.5));\n\
             console.log(Math.round(-2.5));\n\
             var r = Math.round(-0.5);\n\
             console.log(1/r === -1/0 ? '-0' : '0');\n\
             var s = Math.sign(-0);\n\
             console.log(1/s === -1/0 ? '-0' : '0');\n\
             console.log(1/Math.max(-0,+0) === 1/0 ? '+0' : '-0');\n\
             console.log(1/Math.min(+0,-0) === -1/0 ? '-0' : '+0');",
        )
        .unwrap();
        assert_eq!(
            i.output,
            vec!["1", "0", "-1", "-2", "-0", "-0", "+0", "-0"]
        );
    }

    /// ECMA-262 §21.3.2.24/25: Math.max() with no args returns -Infinity;
    /// Math.min() with no args returns +Infinity.
    #[test]
    fn math_max_min_no_args() {
        let i = Interp::new();
        i.install_math();
        let mut i = i;
        i.run(
            "var mx = Math.max();\n\
             var mn = Math.min();\n\
             console.log(mx === -1/0 ? '-Infinity' : String(mx));\n\
             console.log(mn === 1/0  ? 'Infinity'  : String(mn));\n\
             console.log(Math.max(1,3,2));\n\
             console.log(Math.min(1,3,2));",
        )
        .unwrap();
        assert_eq!(
            i.output,
            vec!["-Infinity", "Infinity", "3", "1"],
            "Math.max()/min() no-arg edge cases: got {:?}",
            i.output
        );
    }

    /// ECMA-262 §21.3.2.29: Math.sign edge cases for ±0 and NaN.
    #[test]
    fn math_sign_edge_cases() {
        let i = Interp::new();
        i.install_math();
        let mut i = i;
        // Use x !== x for NaN detection (avoids needing isNaN / install_globals).
        // Use 0/0 for NaN literal (avoids needing the NaN binding too).
        i.run(
            "var sn = Math.sign(-0);\n\
             var sp = Math.sign(+0);\n\
             console.log(1/sn === -1/0 ? '-0' : '0');\n\
             console.log(1/sp === 1/0  ? '+0' : '-0');\n\
             console.log(Math.sign(-5));\n\
             console.log(Math.sign(5));\n\
             var nan_result = Math.sign(0/0);\n\
             console.log(nan_result !== nan_result ? 'NaN' : 'not-NaN');",
        )
        .unwrap();
        assert_eq!(
            i.output,
            vec!["-0", "+0", "-1", "1", "NaN"],
            "Math.sign edge cases: got {:?}",
            i.output
        );
    }

    /// ECMA-262 §21.3.2.28: Math.round half-toward-+Infinity (alias test).
    /// round(-0.5) must equal -0 (not -1); round(-2.5) must equal -2.
    #[test]
    fn math_round_half_toward_positive() {
        let i = Interp::new();
        i.install_math();
        let mut i = i;
        i.run(
            "var r1 = Math.round(-0.5);\n\
             var r2 = Math.round(-2.5);\n\
             console.log(r1 === 0 && 1/r1 === -1/0 ? '-0' : String(r1));\n\
             console.log(r2);",
        )
        .unwrap();
        assert_eq!(
            i.output,
            vec!["-0", "-2"],
            "Math.round half-toward-+Infinity: got {:?}",
            i.output
        );
    }

    /// ECMA-262 §21.3.2.26: Math.pow special cases.
    /// pow(1, NaN) = NaN; pow(-1, ±Infinity) = NaN.
    #[test]
    fn math_pow_ecma_special_cases() {
        let i = Interp::new();
        i.install_math();
        let mut i = i;
        i.run(
            "var p1 = Math.pow(1, 0/0);\n\
             console.log(p1 !== p1 ? 'NaN' : String(p1));\n\
             var p2 = Math.pow(-1, 1/0);\n\
             console.log(p2 !== p2 ? 'NaN' : String(p2));\n\
             var p3 = Math.pow(-1, -1/0);\n\
             console.log(p3 !== p3 ? 'NaN' : String(p3));\n\
             var p4 = 1 ** (0/0);\n\
             console.log(p4 !== p4 ? 'NaN' : String(p4));",
        )
        .unwrap();
        assert_eq!(
            i.output,
            vec!["NaN", "NaN", "NaN", "NaN"],
            "Math.pow ECMAScript special cases: got {:?}",
            i.output
        );
    }

    /// ECMA-262 §21.3.2.18: Math.hypot(Infinity, NaN) = Infinity.
    #[test]
    fn math_hypot_infinity_beats_nan() {
        let i = Interp::new();
        i.install_math();
        let mut i = i;
        i.run(
            "var h = Math.hypot(1/0, 0/0);\n\
             console.log(h === 1/0 ? 'Infinity' : String(h));\n\
             var h2 = Math.hypot(0/0, -1/0);\n\
             console.log(h2 === 1/0 ? 'Infinity' : String(h2));",
        )
        .unwrap();
        assert_eq!(
            i.output,
            vec!["Infinity", "Infinity"],
            "Math.hypot(Infinity, NaN): got {:?}",
            i.output
        );
    }

    /// console.assert(false, msg) must emit output even when called indirectly.
    #[test]
    fn console_assert_false_outputs_message() {
        let (_, out) = run(
            "console.assert(false, 'direct');\n\
             var fn_assert = console.assert;\n\
             fn_assert(false, 'indirect');\n\
             console.assert(true, 'should-not-appear');",
        );
        assert_eq!(
            out,
            vec!["[asrt] Assertion failed: direct", "[asrt] Assertion failed: indirect"],
            "console.assert false outputs message: got {out:?}"
        );
    }

    /// console.assert with no message args emits bare "Assertion failed".
    #[test]
    fn console_assert_false_no_message() {
        let (_, out) = run("console.assert(false);");
        assert_eq!(
            out,
            vec!["[asrt] Assertion failed"],
            "console.assert no-msg: got {out:?}"
        );
    }

    /// ECMA-262 §21.4: new Date(y, mo, …) applies MakeFullYear — years
    /// 0..=99 are treated as 1900+year.
    #[test]
    fn date_make_full_year() {
        let i = Interp::new();
        i.install_math();
        i.install_date();
        let mut i = i;
        i.run(
            "var d = new Date(99, 0, 1);\n\
             console.log(d.getFullYear());\n\
             var d2 = new Date(0, 0, 1);\n\
             console.log(d2.getFullYear());\n\
             var d3 = new Date(100, 0, 1);\n\
             console.log(d3.getFullYear());",
        )
        .unwrap();
        // new Date(99,0,1)  → year 1999 (MakeFullYear: 0..=99 → 1900+y)
        // new Date(0,0,1)   → year 1900 (MakeFullYear: 0 → 1900)
        // new Date(100,0,1) → year 100  (> 99, no mapping)
        assert_eq!(i.output, vec!["1999", "1900", "100"]);
    }

