    // ── AnnexB String.prototype HTML wrappers (B.2.3.2-14) ──
    #[test]
    fn annexb_string_html_wrappers() {
        let (_, out) = run(
            "console.log('_'.anchor('b'));\
             console.log('_'.anchor('\\x22'));\
             console.log('_'.anchor(0x2A));\
             console.log('x'.bold());\
             console.log('x'.italics());\
             console.log('x'.fixed());\
             console.log('x'.fontcolor('red'));\
             console.log('x'.link('u'));\
             console.log(typeof String.prototype.big);",
        );
        assert_eq!(
            out,
            vec![
                "<a name=\"b\">_</a>",
                "<a name=\"&quot;\">_</a>",
                "<a name=\"42\">_</a>",
                "<b>x</b>",
                "<i>x</i>",
                "<tt>x</tt>",
                "<font color=\"red\">x</font>",
                "<a href=\"u\">x</a>",
                "function",
            ]
        );
    }

    // An HTML wrapper called on null/undefined throws TypeError; a throwing
    // attribute `toString` propagates (abrupt completion).
    #[test]
    fn annexb_html_wrapper_coercion_throws() {
        let (_, out) = run(
            "try { String.prototype.bold.call(undefined); console.log('no'); }\
               catch (e) { console.log(e instanceof TypeError); }\
             try { ''.anchor({ toString() { throw new RangeError('x'); } }); console.log('no'); }\
               catch (e) { console.log(e instanceof RangeError); }",
        );
        assert_eq!(out, vec!["true", "true"]);
    }

    // ── AnnexB Date.prototype.getYear/setYear/toUTCString/toGMTString ──
    fn run_with_date(src: &str) -> Vec<String> {
        let mut i = Interp::new();
        i.install_basic_globals();
        i.install_date();
        i.run(src).expect("run");
        i.output
    }

    #[test]
    fn annexb_date_methods() {
        let out = run_with_date(
            "console.log(new Date(1970, 0).getYear());\
             console.log(new Date(1899, 0).getYear());\
             console.log(new Date(2000, 0).getYear());\
             console.log(typeof Date.prototype.getYear);\
             console.log(typeof Date.prototype.setYear);\
             console.log(Date.prototype.toGMTString === Date.prototype.toUTCString);\
             console.log(new Date(0).toUTCString());",
        );
        assert_eq!(
            out,
            vec![
                "70",
                "-1",
                "100",
                "function",
                "function",
                "true",
                "Thu, 01 Jan 1970 00:00:00 GMT",
            ]
        );
    }

    // `Date.prototype.getYear.call(non-date)` throws TypeError (brand check).
    #[test]
    fn annexb_date_method_brand_check() {
        let out = run_with_date(
            "try { Date.prototype.getYear.call({}); console.log('no'); }\
               catch (e) { console.log(e instanceof TypeError); }",
        );
        assert_eq!(out, vec!["true"]);
    }

    // ── `new` enforces IsConstructor (ECMA-262 §13.3.5.1) ──
    // Built-in methods / non-constructor builtins are callable but throw on `new`;
    // genuine constructors keep working.
    #[test]
    fn new_on_non_constructor_throws() {
        let (_, out) = run(
            "function t(f){ try { f(); return 'ok'; } catch (e) { return e instanceof TypeError ? 'TE' : 'other'; } }\
             console.log(t(() => new (String.prototype.slice)()));\
             console.log(t(() => new (String.prototype.big)()));\
             console.log(t(() => new escape()));\
             console.log(t(() => new parseInt()));\
             console.log(t(() => new Symbol()));\
             console.log(t(() => new Map()));\
             console.log(t(() => new Set()));\
             console.log(t(() => new Number(5)));\
             console.log(t(() => new String('x')));\
             console.log(t(() => new Array(3)));\
             console.log(t(() => { class C {} return new C(); }));",
        );
        assert_eq!(
            out,
            vec!["TE", "TE", "TE", "TE", "TE", "ok", "ok", "ok", "ok", "ok", "ok"]
        );
    }

    // `isConstructor(builtinMethod) === false` via the test262 idiom
    // `Reflect.construct(function(){}, [], f)`.
    #[test]
    fn reflect_construct_newtarget_non_constructor() {
        let out = run_with_date(
            "function isCtor(f){ if (typeof f !== 'function') return 'notfn';\
               try { Reflect.construct(function(){}, [], f); return true; } catch (e) { return false; } }\
             console.log(isCtor(String.prototype.big));\
             console.log(isCtor(Date.prototype.getYear));\
             console.log(isCtor(Array));\
             console.log(isCtor(Map));",
        );
        assert_eq!(out, vec!["false", "false", "true", "true"]);
    }

