    #[test]
    fn async_await_runs_through_synchronously() {
        // `await x` unwraps `x`; the body executes top-to-bottom (we don't
        // suspend). Per ECMA-262 an async function returns a PROMISE, so the
        // result is consumed via `.then`. The settled promise's reaction runs
        // when `run()` drains microtasks.
        let mut i = Interp::new();
        i.install_promise();
        i.run(
            "async function fetcher() { let x = await 7; return x + 1; }\
             fetcher().then(v => console.log(v));",
        )
        .unwrap();
        assert_eq!(i.output, vec!["8"]);
    }

    #[test]
    fn async_function_body_throw_becomes_rejected_promise() {
        // A thrown async body must NOT propagate synchronously — it becomes a
        // rejected promise. A fire-and-forget call therefore does not abort
        // the surrounding synchronous code (the wagmi `createConfig` crash).
        let mut i = Interp::new();
        i.install_promise();
        i.run(
            "let reached = false;\
             async function boom() { throw new Error('nope'); }\
             function setup() { boom().catch(() => {}); reached = true; return 42; }\
             let v = setup();\
             console.log(reached, v);",
        )
        .unwrap();
        assert_eq!(i.output, vec!["true 42"]);
    }

    #[test]
    fn promise_resolve_then() {
        let i = Interp::new();
        i.install_promise();
        let mut i = i;
        i.run(
            "Promise.resolve(42).then(x => console.log('got', x));\
             Promise.resolve(10).then(x => x * 2).then(x => console.log('doubled', x));\
             Promise.reject('boom').catch(e => console.log('caught', e));\
             Promise.reject('a').then(v => v, e => console.log('rejected via then:', e));",
        )
        .unwrap();
        // After the move to a real microtask queue, multi-step Promise
        // chains interleave with single-step chains: every `.then()`
        // boundary defers to the next microtask tick, so the second
        // step of the `doubled` chain runs after the other three single-
        // step chains' first ticks. This matches V8/SpiderMonkey
        // ordering.
        assert_eq!(
            i.output,
            vec![
                "got 42",
                "caught boom",
                "rejected via then: a",
                "doubled 20",
            ]
        );
    }

