    #[test]
    fn promise_race_waits_for_first_settlement() {
        let i = Interp::new();
        i.install_promise();
        let mut i = i;
        i.run(
            "var slow = Promise.withResolvers();\
             var fast = Promise.withResolvers();\
             Promise.race([slow.promise, fast.promise]).then(v => console.log('race ' + v));\
             fast.resolve('win');\
             slow.resolve('lose');",
        )
        .unwrap();
        assert_eq!(i.output, vec!["race win"]);
    }

