    #[test]
    fn host_object_round_trip() {
        // Browser pattern: install a `document` host object, script mutates
        // a field, browser reads it back.
        use crate::ordered::OrderedMap as HashMap;
        use std::cell::RefCell;
        use std::rc::Rc;

        let interp = Interp::new();
        let mut map: HashMap<String, Value> = HashMap::new();
        map.insert("title".into(), Value::String("initial".into()));
        let doc = Value::Object(Rc::new(RefCell::new(map)));
        interp.define_global("document", doc);

        let mut i = interp;
        i.run("document.title = 'changed';").unwrap();
        match i.get_global("document").unwrap() {
            Value::Object(o) => {
                assert!(
                    matches!(o.borrow().get("title"), Some(Value::String(s)) if &**s == "changed")
                );
            }
            _ => panic!("document not an object"),
        }
    }

