    #[test]
    fn for_of_custom_symbol_iterator_on_object() {
        // A plain object with a custom [Symbol.iterator] must have its
        // iterator driven — not the iterable_values fast path.
        let (_, out) = run(
            "const obj = { \
                [Symbol.iterator]: function() { \
                    let i = 0; \
                    return { next: function() { \
                        if (i < 3) return { value: i++, done: false }; \
                        return { done: true }; \
                    }}; \
                } \
            }; \
            const out = []; \
            for (const v of obj) out.push(v); \
            console.log(out.join(','));",
        );
        assert_eq!(out, vec!["0,1,2"]);
    }

