    #[test]
    fn generator_is_iterable_via_symbol_iterator() {
        // A generator object must have `[Symbol.iterator]()` returning itself,
        // so it is iterable (both for-of and [...gen] work).
        let (_, out) = run(
            "function* gen() { yield 1; yield 2; yield 3; } \
            const g = gen(); \
            const got = []; \
            for (const v of g) got.push(v); \
            console.log(got.join(','));",
        );
        assert_eq!(out, vec!["1,2,3"]);
    }

    #[test]
    fn generator_symbol_iterator_returns_self() {
        // gen[Symbol.iterator]() === gen per ECMA-262 §27.5.1.1.
        let (_, out) = run(
            "function* gen() { yield 1; } \
            const g = gen(); \
            console.log(g[Symbol.iterator]() === g);",
        );
        assert_eq!(out, vec!["true"]);
    }

    #[test]
    fn for_of_generator_lazily_driven() {
        // for-of over a generator must NOT materialise all values upfront —
        // early break must work and must not drain the rest.
        let (_, out) = run(
            "function* counter() { let n = 0; while(true) { yield n++; } } \
            const gen = counter(); \
            const got = []; \
            for (const v of gen) { got.push(v); if (v >= 2) break; } \
            console.log(got.join(','));",
        );
        // Should yield 0, 1, 2 and then break — no infinite loop.
        assert_eq!(out, vec!["0,1,2"]);
    }

