    #[test]
    fn optional_chain_full_short_circuit() {
        // a?.b.c must NOT throw when a is null — entire chain short-circuits
        let (_, out) = run("var a = null; console.log(String(a?.b.c));");
        assert!(out.iter().any(|s| s.contains("undefined")), "null?.b.c should be undefined, got: {out:?}");
        // non-null should work normally
        let (_, out) = run("var a = {b:{c:42}}; console.log(a?.b.c);");
        assert!(out.iter().any(|s| s.contains("42")), "non-null chain, got: {out:?}");
        // double ?.
        let (_, out) = run("var x = {a:null}; console.log(String(x?.a?.b));");
        assert!(out.iter().any(|s| s.contains("undefined")), "x?.a?.b when a=null, got: {out:?}");
        // method call in chain
        let (_, out) = run("var a = null; console.log(String(a?.foo.bar()));");
        assert!(out.iter().any(|s| s.contains("undefined")), "null?.foo.bar() should be undefined, got: {out:?}");
        // 3-level chain: x?.foo.bar.baz must short-circuit all 3 accesses
        let (_, out) = run("var x = null; console.log(String(x?.foo.bar.baz));");
        assert!(out.iter().any(|s| s.contains("undefined")), "null?.foo.bar.baz should be undefined, got: {out:?}");
        // call followed by member: x?.fn().bar
        let (_, out) = run("var x = null; console.log(String(x?.fn().bar));");
        assert!(out.iter().any(|s| s.contains("undefined")), "null?.fn().bar should be undefined, got: {out:?}");
        // non-null call-then-member: should work
        let (_, out) = run("var x = {fn: function() { return {bar: 99}; }}; console.log(x?.fn().bar);");
        assert!(out.iter().any(|s| s.contains("99")), "non-null fn().bar, got: {out:?}");
        // x?.fn() when x is null
        let (_, out) = run("var x = null; console.log(String(x?.fn()));");
        assert!(out.iter().any(|s| s.contains("undefined")), "null?.fn() should be undefined, got: {out:?}");
    }

    #[test]
    fn tagged_template_segments_and_interp() {
        let (_, out) = run(r#"
            function tag(strings) { return strings.length + ':' + strings[0] + '|' + (strings[1] || ''); }
            console.log(tag`hello ${42} world`);
        "#);
        assert!(out.iter().any(|s| s.contains("2:hello ")), "got: {out:?}");
        // strings.raw must be set
        let (_, out) = run(r#"
            function tag(s) { return s.raw ? 'has_raw' : 'no_raw'; }
            console.log(tag`hello`);
        "#);
        assert!(out.iter().any(|s| s.contains("has_raw")), "got: {out:?}");
        // interpolation values passed as separate args
        let (_, out) = run(r#"
            function tag(strings, ...vals) { return vals.join(','); }
            var x = 10; var y = 20;
            console.log(tag`${x}+${y}`);
        "#);
        assert!(out.iter().any(|s| s.contains("10,20")), "got: {out:?}");
        // tag`a` with no interpolations: strings = ["a"], no extra args
        let (_, out) = run(r#"
            function tag(strings, ...vals) { return strings.length + ',' + vals.length + ':' + strings[0]; }
            console.log(tag`a`);
        "#);
        assert!(out.iter().any(|s| s.contains("1,0:a")), "tag`a` should give 1 segment 0 values, got: {out:?}");
        // tag`hello ${1} world ${2}` — approximate form from task spec
        let (_, out) = run(r#"
            function tag(strings, ...values) { return strings.join('') + ' ' + values.join(','); }
            console.log(tag`hello ${1} world ${2}`);
        "#);
        assert!(out.iter().any(|s| s.contains("1,2")), "tag with 2 values, got: {out:?}");
    }

    #[test]
    fn tagged_template_raw_array_preserves_backslashes() {
        // strings.raw must have literal backslash-preserved text:
        //   - cooked[0] = newline char (from \n)
        //   - raw[0]    = literal two chars: backslash + n
        let (_, out) = run(r#"
            function tag(s) { return s.raw[0]; }
            console.log(tag`\n`);
        "#);
        // Raw should be "\n" (two chars: backslash + n), not a newline
        assert_eq!(out, vec!["\\n"], "raw[0] should be literal backslash-n, got: {out:?}");

        // Cooked should be an actual newline
        let (_, out) = run(r#"
            function tag(s) { return s[0].charCodeAt(0); }
            console.log(tag`\n`);
        "#);
        assert_eq!(out, vec!["10"], "cooked[0] should be newline (code 10), got: {out:?}");

        // String.raw builtin: returns raw joined segments with interpolations
        let (_, out) = run(r#"
            const n = 'world';
            console.log(String.raw`Hello\nworld`);
        "#);
        assert_eq!(out, vec!["Hello\\nworld"], "String.raw should preserve backslash, got: {out:?}");

        // Multiple escape types in .raw
        let (_, out) = run(r#"
            function tag(s) { return s.raw[0]; }
            console.log(tag`\t\r\n`);
        "#);
        assert_eq!(out, vec!["\\t\\r\\n"], "raw should preserve all backslash sequences, got: {out:?}");
    }

    // ── Bug 1: Array.join / toString must render null/undefined as "" ────────
    #[test]
    fn array_join_null_undefined_render_as_empty_string() {
        // [1, null, 3].join('-') → "1--3" (null becomes "", per ECMA §23.1.3.30)
        let (_, out) = run("console.log([1, null, 3].join('-'));");
        assert_eq!(out, vec!["1--3"], "join('-') with null: got {out:?}");

        // Array.prototype.toString (default join(",")) for mixed null/undefined
        let (_, out) = run("console.log(String([null, undefined, 1]));");
        assert_eq!(out, vec![",,1"], "String([null,undefined,1]): got {out:?}");

        // Explicit join with undefined element
        let (_, out) = run("var a = [1]; a[3] = 4; console.log(a.join('-'));");
        assert_eq!(out, vec!["1---4"], "sparse array join: got {out:?}");
    }

    // ── Bug 2: JSON.stringify with indent keeps insertion order ──────────────
    #[test]
    fn json_stringify_pretty_preserves_insertion_order() {
        // Keys must appear in insertion order (b before a), NOT sorted.
        let mut i = Interp::new();
        i.install_basic_globals();
        i.install_json();
        i.run(r#"console.log(JSON.stringify({b:1,a:2},null,2));"#).unwrap();
        let s = i.output.join("");
        let b_pos = s.find("\"b\"").expect("key b missing");
        let a_pos = s.find("\"a\"").expect("key a missing");
        assert!(b_pos < a_pos, "key 'b' should appear before 'a', got: {s:?}");
    }

    // ── Bug 3: JSON.parse combines UTF-16 surrogate pairs ───────────────────
    #[test]
    fn json_parse_surrogate_pairs_become_astral_char() {
        let mut i = Interp::new();
        i.install_basic_globals();
        i.install_json();
        // 😀 is U+1F600, encoded as 😀 in UTF-16 surrogate pairs.
        i.run(r#"console.log(JSON.parse('"\\uD83D\\uDE00"'));"#).unwrap();
        assert_eq!(i.output, vec!["😀"], "surrogate-pair decode: got {:?}", i.output);

        // A lone high surrogate with no following low surrogate → U+FFFD.
        let mut j = Interp::new();
        j.install_basic_globals();
        j.install_json();
        j.run(r#"console.log(JSON.parse('"\\uD800"').charCodeAt(0));"#).unwrap();
        assert_eq!(j.output, vec!["65533"], "lone high surrogate → U+FFFD: got {:?}", j.output);
    }

    // ── Bug 4: String.prototype.split() with no arg returns ["whole string"] ─
    #[test]
    fn string_split_no_arg_returns_single_element_array() {
        // No separator → single-element array containing the whole string.
        let (_, out) = run(r#"console.log("hello".split().length);"#);
        assert_eq!(out, vec!["1"], "split() length: got {out:?}");

        let (_, out) = run(r#"console.log("hello".split()[0]);"#);
        assert_eq!(out, vec!["hello"], "split()[0]: got {out:?}");

        // Explicit undefined separator is the same as absent.
        let (_, out) = run(r#"console.log("hello".split(undefined).length);"#);
        assert_eq!(out, vec!["1"], "split(undefined) length: got {out:?}");

        // Empty string separator still splits into chars.
        let (_, out) = run(r#"console.log("ab".split("").length);"#);
        assert_eq!(out, vec!["2"], r#"split("") length: got {out:?}"#);
    }

    // ── Bug 5: loose_eq coerces Object/Array via ToPrimitive ────────────────
    #[test]
    fn loose_eq_array_and_object_vs_primitive() {
        // [1] == 1 → Array→"1"→1 == 1 → true
        let (_, out) = run("console.log([1] == 1);");
        assert_eq!(out, vec!["true"], "[1] == 1: got {out:?}");

        // [] == "" → Array→"" == "" → true
        let (_, out) = run(r#"console.log([] == "");"#);
        assert_eq!(out, vec!["true"], r#"[] == "": got {out:?}"#);

        // [] == 0 → Array→""→0 == 0 → true
        let (_, out) = run("console.log([] == 0);");
        assert_eq!(out, vec!["true"], "[] == 0: got {out:?}");

        // [1,2] == "1,2" → Array→"1,2" == "1,2" → true
        let (_, out) = run(r#"console.log([1,2] == "1,2");"#);
        assert_eq!(out, vec!["true"], r#"[1,2] == "1,2": got {out:?}"#);
    }

