    // ── Bug fix: Promise.finally thenable return delays settlement ───────────
    #[test]
    fn promise_finally_thenable_return_delays_with_original_value() {
        let out = run_async(
            "var r = ''; \
             Promise.resolve('orig') \
               .finally(function() { \
                 return Promise.resolve('ignored'); \
               }) \
               .then(function(v) { r = v; }) \
               .then(function() { console.log(r); });",
        );
        // The thenable from finally should be awaited; the derived promise
        // should settle with the ORIGINAL value 'orig', not 'ignored'.
        assert_eq!(out, vec!["orig"], "finally thenable: original value passes through: got {out:?}");
    }

    // ── Bug fix: Promise.finally thenable reject delays and re-rejects ───────
    #[test]
    fn promise_finally_thenable_return_on_rejection() {
        let out = run_async(
            "var r = ''; \
             Promise.reject('reason') \
               .finally(function() { \
                 return Promise.resolve('ignored'); \
               }) \
               .catch(function(e) { r = e; }) \
               .then(function() { console.log(r); });",
        );
        // The rejection reason should be preserved even after a thenable finally.
        assert_eq!(out, vec!["reason"], "finally thenable on reject: original reason passes through: got {out:?}");
    }

