    // ── Bug 2: JIT LoadUndef → NaN ──────────────────────────────────────────
    #[test]
    fn jit_undef_param_is_nan() {
        // When a JIT-compiled function is called with fewer args than params,
        // the missing param should be NaN (not 0.0 or a stale register).
        // Call 15 times (> JIT_THRESHOLD=12) so the function goes JIT-compiled.
        let (_, out) = run(
            "function f(a, b) { return a + b; } \
             var result; \
             for (var i = 0; i < 15; i++) { result = f(1); } \
             console.log(isNaN(result));",
        );
        assert_eq!(out, vec!["true"], "undef param NaN: got {out:?}");
    }

